(() => {
  // Initialize bot storage and rating system
  oc.thread.customData ??= {};
  oc.character.customData ??= {};
  oc.character.customData.PUBLIC ??= {};

  // Initialize rating tracking
  oc.character.customData.PUBLIC.promptDatabase ??= [];
  oc.character.customData.PUBLIC.averageRating ??= 0;
  oc.character.customData.PUBLIC.totalPrompts ??= 0;
  oc.character.customData.PUBLIC.improvementMetrics ??= {
    topRatedPatterns: [],
    commonSuccessElements: [],
    failureLog: []
  };

  // Thread-level tracking
  oc.thread.customData.currentPrompt ??= null;
  oc.thread.customData.promptHistory ??= [];
  oc.thread.customData.sessionRatings ??= [];

  // Process rating commands
  const processRating = (ratingValue, comment = '') => {
    if (!oc.thread.customData.currentPrompt) return;

    const rating = {
      timestamp: Date.now(),
      prompt: oc.thread.customData.currentPrompt,
      rating: ratingValue,
      comment: comment
    };

    oc.thread.customData.sessionRatings.push(rating);
    oc.character.customData.PUBLIC.promptDatabase.push(rating);
    oc.character.customData.PUBLIC.totalPrompts++;

    // Calculate average rating
    const sum = oc.character.customData.PUBLIC.promptDatabase.reduce((acc, r) => acc + r.rating, 0);
    oc.character.customData.PUBLIC.averageRating = sum / oc.character.customData.PUBLIC.promptDatabase.length;

    // Extract and analyze successful patterns from high-rated prompts
    if (ratingValue >= 4) {
      analyzeSuccessPatterns(oc.thread.customData.currentPrompt);
    } else if (ratingValue <= 2) {
      logFailure(oc.thread.customData.currentPrompt, comment);
    }
  };

  // Analyze successful prompt patterns
  const analyzeSuccessPatterns = (prompt) => {
    const patterns = prompt.match(/[\w\s]+(?=,|\.|$)/g) || [];
    const metrics = oc.character.customData.PUBLIC.improvementMetrics;

    patterns.forEach(pattern => {
      const normalized = pattern.trim().toLowerCase();
      if (normalized.length > 3) {
        const existing = metrics.commonSuccessElements.find(e => e.pattern === normalized);
        if (existing) {
          existing.frequency++;
        } else {
          metrics.commonSuccessElements.push({ pattern: normalized, frequency: 1 });
        }
      }
    });

    metrics.commonSuccessElements.sort((a, b) => b.frequency - a.frequency);
  };

  // Log failures for analysis
  const logFailure = (prompt, comment) => {
    oc.character.customData.PUBLIC.improvementMetrics.failureLog.push({
      prompt: prompt,
      comment: comment,
      timestamp: Date.now()
    });
  };

  // Generate improvement-based prompt
  const generateImprovedPrompt = (userRequest) => {
    const metrics = oc.character.customData.PUBLIC.improvementMetrics;
    const successElements = metrics.commonSuccessElements.slice(0, 5).map(e => e.pattern).join(', ');

    const improvedPrompt = `Based on ${oc.character.customData.PUBLIC.totalPrompts} previous generations (avg rating: ${oc.character.customData.PUBLIC.averageRating.toFixed(2)}/5):\n\nUser Request: ${userRequest}\n\nIncorporating successful elements: ${successElements}\n\nGenerated Prompt: [Detailed explicit NSFW prompt incorporating user request and successful patterns]`;

    return improvedPrompt;
  };

  // Setup message event listener
  oc.thread.on('MessageAdded', (message) => {
    if (message.author === 'user') {
      const content = message.content.toLowerCase();

      // Handle rating commands
      if (content.includes('rate:')) {
        const ratingMatch = content.match(/rate:\s*(\d+)/i);
        if (ratingMatch) {
          const rating = Math.min(5, Math.max(1, parseInt(ratingMatch[1])));
          const comment = content.replace(/rate:\s*\d+/i, '').trim();
          processRating(rating, comment);

          // Add confirmation message
          oc.thread.messages.push({
            content: `✓ Rating recorded: ${rating}/5${comment ? '\nFeedback: ' + comment : ''}\n\nImprovement tracking:\n- Total prompts: ${oc.character.customData.PUBLIC.totalPrompts}\n- Average rating: ${oc.character.customData.PUBLIC.averageRating.toFixed(2)}/5\n- Top success patterns: ${oc.character.customData.PUBLIC.improvementMetrics.commonSuccessElements.slice(0, 3).map(p => p.pattern).join(', ') || 'Building database...'}`,
            author: 'system',
            expectsReply: false,
            hiddenFrom: ['ai']
          });
        }
      }

      // Handle improvement request
      if (content.includes('improve') || content.includes('better')) {
        oc.thread.customData.improveMode = true;
      }

      // Handle stats request
      if (content.includes('stats') || content.includes('progress')) {
        const stats = `📊 Self-Improvement Statistics:\n- Prompts generated: ${oc.character.customData.PUBLIC.totalPrompts}\n- Average quality: ${oc.character.customData.PUBLIC.averageRating.toFixed(2)}/5\n- Session ratings: ${oc.thread.customData.sessionRatings.length}\n- Success patterns identified: ${oc.character.customData.PUBLIC.improvementMetrics.commonSuccessElements.length}\n- Top patterns: ${oc.character.customData.PUBLIC.improvementMetrics.commonSuccessElements.slice(0, 5).map(p => `${p.pattern}(${p.frequency}x)`).join(', ') || 'None yet'}\n- Failures logged: ${oc.character.customData.PUBLIC.improvementMetrics.failureLog.length}`;

        oc.thread.messages.push({
          content: stats,
          author: 'system',
          expectsReply: false,
          hiddenFrom: ['ai']
        });
      }
    }
  });

  // Setup shortcut buttons for common interactions
  oc.thread.shortcutButtons = [
    {
      name: '⭐ Rate 5/5',
      message: 'rate: 5 Excellent quality, exactly what I wanted',
      insertionType: 'replace',
      autoSend: true,
      clearAfterSend: true
    },
    {
      name: '👍 Rate 4/5',
      message: 'rate: 4 Good, could use minor improvements',
      insertionType: 'replace',
      autoSend: true,
      clearAfterSend: true
    },
    {
      name: '👌 Rate 3/5',
      message: 'rate: 3 Acceptable but needs work',
      insertionType: 'replace',
      autoSend: true,
      clearAfterSend: true
    },
    {
      name: '⬇️ Rate 2/5',
      message: 'rate: 2 Poor quality or missing elements',
      insertionType: 'replace',
      autoSend: true,
      clearAfterSend: true
    },
    {
      name: '❌ Rate 1/5',
      message: 'rate: 1 Unacceptable, major problems',
      insertionType: 'replace',
      autoSend: true,
      clearAfterSend: true
    },
    {
      name: '📈 Improve Mode',
      message: 'Use your learning from previous ratings to generate an improved version of that prompt',
      insertionType: 'replace',
      autoSend: true,
      clearAfterSend: true
    },
    {
      name: '📊 Show Stats',
      message: 'stats',
      insertionType: 'replace',
      autoSend: true,
      clearAfterSend: true
    }
  ];

  // Expose functions globally for advanced usage
  window.imageBot = {
    processRating: processRating,
    getStats: () => ({
      totalPrompts: oc.character.customData.PUBLIC.totalPrompts,
      averageRating: oc.character.customData.PUBLIC.averageRating,
      successPatterns: oc.character.customData.PUBLIC.improvementMetrics.commonSuccessElements,
      failureCount: oc.character.customData.PUBLIC.improvementMetrics.failureLog.length
    }),
    improveNextPrompt: (request) => generateImprovedPrompt(request),
    getCurrentDatabase: () => oc.character.customData.PUBLIC.promptDatabase
  };
})();
